import{_ as i,o as l,c as a,ag as o}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"QiNote Salvage Extract","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/120_applications/qinote/qinote_salvage_extract.md","filePath":"10_core/40_service_apps/120_applications/qinote/qinote_salvage_extract.md"}'),t={name:"10_core/40_service_apps/120_applications/qinote/qinote_salvage_extract.md"};function r(n,e,s,d,c,u){return l(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="qinote-salvage-extract" tabindex="-1">QiNote Salvage Extract <a class="header-anchor" href="#qinote-salvage-extract" aria-label="Permalink to &quot;QiNote Salvage Extract&quot;">​</a></h1><h2 id="retired-project-carry-forward-map" tabindex="-1">Retired Project Carry-Forward Map <a class="header-anchor" href="#retired-project-carry-forward-map" aria-label="Permalink to &quot;Retired Project Carry-Forward Map&quot;">​</a></h2><h3 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h3><p>This document preserves the durable ideas, goals, constraints, and module requirements from the retiring project that should be carried forward into <strong>QiNote</strong>.</p><p>The extraction rule is simple:</p><p><strong>Preserve principles, architecture, workflows, and long-term goals. Do not preserve obsolete scaffolding, duplicate trees, or project-specific clutter.</strong></p><hr><h1 id="_1-qinote-identity" tabindex="-1">1. QiNote Identity <a class="header-anchor" href="#_1-qinote-identity" aria-label="Permalink to &quot;1. QiNote Identity&quot;">​</a></h1><h2 id="_1-1-definition" tabindex="-1">1.1 Definition <a class="header-anchor" href="#_1-1-definition" aria-label="Permalink to &quot;1.1 Definition&quot;">​</a></h2><p><strong>QiNote is the local-first note, knowledge, memory, and retrieval layer of the Qi ecosystem.</strong></p><p>It is not merely a note-taking app. It is the system that turns personal, household, legal, financial, technical, and operational information into durable, searchable, structured knowledge.</p><h2 id="_1-2-platform-role" tabindex="-1">1.2 Platform Role <a class="header-anchor" href="#_1-2-platform-role" aria-label="Permalink to &quot;1.2 Platform Role&quot;">​</a></h2><p>QiNote belongs inside the broader QiOne / QiAccess / QiNexus ecosystem:</p><ul><li><strong>QiAccess</strong> = front door, interface, and launchpad</li><li><strong>QiNexus</strong> = human workspace and source library</li><li><strong>QiArchive</strong> = AI memory pipeline, ingestion, extraction, chunking, embeddings, graph, and backups</li><li><strong>QiLabs</strong> = code, execution, tooling, and experiments</li><li><strong>QiNote</strong> = local-first knowledge, note, memory, and retrieval module</li><li><strong>QiGraph</strong> = graph, relationship visualization, and intelligence layer</li><li><strong>Paperless-NGX</strong> = document intake, OCR, and document processing plant</li><li><strong>Qdrant</strong> = vector search and semantic retrieval</li><li><strong>Neo4j</strong> = relationship graph</li><li><strong>Ollama / Open WebUI</strong> = local AI interaction layer</li></ul><h2 id="_1-3-core-positioning" tabindex="-1">1.3 Core Positioning <a class="header-anchor" href="#_1-3-core-positioning" aria-label="Permalink to &quot;1.3 Core Positioning&quot;">​</a></h2><p>QiNote should become the long-term engine for:</p><ul><li>atomic notes</li><li>structured objects</li><li>source-backed recall</li><li>personal knowledge management</li><li>AI-readable memory</li><li>timeline reconstruction</li><li>document intelligence</li><li>graph-based relationships</li><li>local-first private retrieval</li><li>publishable and private knowledge views</li></ul><p>Short-term tools like Obsidian, Capacities, Wiki.js, or static sites can be used as bridges, but QiNote is the eventual owned system.</p><hr><h1 id="_2-non-negotiable-doctrine" tabindex="-1">2. Non-Negotiable Doctrine <a class="header-anchor" href="#_2-non-negotiable-doctrine" aria-label="Permalink to &quot;2. Non-Negotiable Doctrine&quot;">​</a></h1><h2 id="_2-1-source-files-remain-truth" tabindex="-1">2.1 Source Files Remain Truth <a class="header-anchor" href="#_2-1-source-files-remain-truth" aria-label="Permalink to &quot;2.1 Source Files Remain Truth&quot;">​</a></h2><p>The canonical truth must remain in durable source files, documents, or structured records.</p><p>Derived systems must never become the only copy of truth.</p><p>Derived systems include:</p><ul><li>vector indexes</li><li>graph indexes</li><li>generated summaries</li><li>AI memory</li><li>dashboards</li><li>search APIs</li><li>static published views</li><li>Graphify outputs</li><li>admin panels</li></ul><p>All derived objects must point back to source.</p><h2 id="_2-2-local-first-cloud-backed" tabindex="-1">2.2 Local-First, Cloud-Backed <a class="header-anchor" href="#_2-2-local-first-cloud-backed" aria-label="Permalink to &quot;2.2 Local-First, Cloud-Backed&quot;">​</a></h2><p>QiNote should be private and local-first by default.</p><p>Preferred model:</p><ul><li>local SSD or server cache for active processing</li><li>Google Drive / QiNexus as the cloud-backed source library</li><li>private qiserver runtime for services</li><li>Tailscale / Cloudflare only for controlled access</li><li>no public exposure unless explicitly intended</li></ul><h2 id="_2-3-human-readable-names-stable-ids" tabindex="-1">2.3 Human-Readable Names + Stable IDs <a class="header-anchor" href="#_2-3-human-readable-names-stable-ids" aria-label="Permalink to &quot;2.3 Human-Readable Names + Stable IDs&quot;">​</a></h2><p>Files and notes should have clean names humans can understand, but every important object must also have stable machine identity.</p><p>Preferred principles:</p><ul><li>human-readable display names</li><li>stable canonical IDs underneath</li><li>short visible suffixes where useful</li><li>metadata-first indexing</li><li>deterministic naming where possible</li><li>IDs that survive file moves and renames</li></ul><h2 id="_2-4-metadata-before-automation" tabindex="-1">2.4 Metadata Before Automation <a class="header-anchor" href="#_2-4-metadata-before-automation" aria-label="Permalink to &quot;2.4 Metadata Before Automation&quot;">​</a></h2><p>Do not automate chaos.</p><p>QiNote should prioritize clean metadata, source identity, ingestion state, and object classification before advanced AI automation.</p><p>The AI layer should enrich and retrieve. It should not invent structure where none exists.</p><h2 id="_2-5-one-home-per-concern" tabindex="-1">2.5 One Home Per Concern <a class="header-anchor" href="#_2-5-one-home-per-concern" aria-label="Permalink to &quot;2.5 One Home Per Concern&quot;">​</a></h2><p>Each concern needs a clear owner.</p><p>Examples:</p><ul><li>Documents and source assets live in QiNexus / QiArchive paths.</li><li>Notes and knowledge objects live in QiNote.</li><li>OCR intake belongs to Paperless-NGX.</li><li>AI indexing belongs to QiArchive / ingestion services.</li><li>Relationship mapping belongs to Neo4j / QiGraph.</li><li>Semantic retrieval belongs to Qdrant.</li><li>Front-door navigation belongs to QiAccess.</li></ul><p>Avoid duplicate folder trees, duplicate registries, and multiple competing “truth” locations.</p><h2 id="_2-6-derived-systems-must-reference-source" tabindex="-1">2.6 Derived Systems Must Reference Source <a class="header-anchor" href="#_2-6-derived-systems-must-reference-source" aria-label="Permalink to &quot;2.6 Derived Systems Must Reference Source&quot;">​</a></h2><p>Every chunk, embedding, graph node, summary, and AI answer must be traceable back to source.</p><p>Minimum lineage fields:</p><ul><li><code>source_id</code></li><li><code>source_path</code></li><li><code>document_id</code></li><li><code>chunk_id</code></li><li><code>hash</code></li><li><code>created_at</code></li><li><code>ingestion_run_id</code></li><li><code>extraction_method</code></li><li><code>status</code></li></ul><h2 id="_2-7-lightweight-adrs" tabindex="-1">2.7 Lightweight ADRs <a class="header-anchor" href="#_2-7-lightweight-adrs" aria-label="Permalink to &quot;2.7 Lightweight ADRs&quot;">​</a></h2><p>Architectural decisions should be recorded as lightweight ADRs when they affect long-term structure.</p><p>Use ADRs for:</p><ul><li>storage doctrine</li><li>ingestion doctrine</li><li>naming standards</li><li>ID strategy</li><li>exposure and security rules</li><li>module ownership</li><li>canonical pipeline changes</li></ul><p>Do not bury major decisions in random chat notes.</p><hr><h1 id="_3-core-qinote-goals" tabindex="-1">3. Core QiNote Goals <a class="header-anchor" href="#_3-core-qinote-goals" aria-label="Permalink to &quot;3. Core QiNote Goals&quot;">​</a></h1><h2 id="_3-1-capture-fast-structure-later" tabindex="-1">3.1 Capture Fast, Structure Later <a class="header-anchor" href="#_3-1-capture-fast-structure-later" aria-label="Permalink to &quot;3.1 Capture Fast, Structure Later&quot;">​</a></h2><p>QiNote must support low-friction capture from multiple inputs:</p><ul><li>quick notes</li><li>tasks and reminders</li><li>care observations</li><li>legal and finance notes</li><li>links</li><li>voice notes</li><li>screenshots</li><li>PDFs</li><li>scans</li><li>documents</li><li>project notes</li><li>journal entries</li></ul><p>Capture should go to a safe inbox first, then be processed.</p><h2 id="_3-2-turn-notes-into-objects" tabindex="-1">3.2 Turn Notes Into Objects <a class="header-anchor" href="#_3-2-turn-notes-into-objects" aria-label="Permalink to &quot;3.2 Turn Notes Into Objects&quot;">​</a></h2><p>QiNote should not be only page-based. It should understand knowledge objects.</p><p>Core object ontology:</p><ol><li>Person</li><li>Project</li><li>Document</li><li>Note / Idea</li><li>Task</li><li>Event</li><li>Topic / Concept</li><li>Source</li></ol><p>Future objects may include:</p><ul><li>Account</li><li>Vendor</li><li>Case</li><li>Asset</li><li>Location</li><li>Timeline Item</li><li>Decision</li><li>Evidence Item</li><li>Routine</li><li>System Component</li></ul><h2 id="_3-3-make-recall-source-backed" tabindex="-1">3.3 Make Recall Source-Backed <a class="header-anchor" href="#_3-3-make-recall-source-backed" aria-label="Permalink to &quot;3.3 Make Recall Source-Backed&quot;">​</a></h2><p>The goal is not generic chat. The goal is accurate recall.</p><p>QiNote should answer questions like:</p><ul><li>“What did I decide about this?”</li><li>“Where is the source document?”</li><li>“What changed since last time?”</li><li>“What evidence supports this?”</li><li>“What tasks came from this note?”</li><li>“What people, projects, and documents are connected?”</li><li>“What is the timeline?”</li></ul><p>Every serious answer should be grounded in source references.</p><h2 id="_3-4-support-timeline-reconstruction" tabindex="-1">3.4 Support Timeline Reconstruction <a class="header-anchor" href="#_3-4-support-timeline-reconstruction" aria-label="Permalink to &quot;3.4 Support Timeline Reconstruction&quot;">​</a></h2><p>QiNote should help reconstruct timelines from:</p><ul><li>notes</li><li>documents</li><li>emails</li><li>calendar events</li><li>logs</li><li>screenshots</li><li>receipts</li><li>legal filings</li><li>project updates</li><li>journal entries</li></ul><p>Timeline support is central, especially for legal, finance, care, and project work.</p><h2 id="_3-5-enable-private-ai-memory" tabindex="-1">3.5 Enable Private AI Memory <a class="header-anchor" href="#_3-5-enable-private-ai-memory" aria-label="Permalink to &quot;3.5 Enable Private AI Memory&quot;">​</a></h2><p>QiNote should become the user-owned memory layer.</p><p>Not vague “AI remembers things.” Real memory means:</p><ul><li>source-backed notes</li><li>structured objects</li><li>canonical IDs</li><li>embeddings</li><li>graph relationships</li><li>ingestion logs</li><li>confidence states</li><li>review workflows</li><li>privacy controls</li></ul><hr><h1 id="_4-qinote-architecture-to-preserve" tabindex="-1">4. QiNote Architecture to Preserve <a class="header-anchor" href="#_4-qinote-architecture-to-preserve" aria-label="Permalink to &quot;4. QiNote Architecture to Preserve&quot;">​</a></h1><h2 id="_4-1-high-level-architecture" tabindex="-1">4.1 High-Level Architecture <a class="header-anchor" href="#_4-1-high-level-architecture" aria-label="Permalink to &quot;4.1 High-Level Architecture&quot;">​</a></h2><p>Preferred spine:</p><p>Source files / notes / docs<br> → detect<br> → register canonical identity<br> → normalize filename<br> → extract text<br> → enrich metadata<br> → chunk<br> → embed locally<br> → store vectors<br> → create or update graph nodes<br> → expose searchable API<br> → show in QiAccess / QiNote UI</p><h2 id="_4-2-canonical-pipeline" tabindex="-1">4.2 Canonical Pipeline <a class="header-anchor" href="#_4-2-canonical-pipeline" aria-label="Permalink to &quot;4.2 Canonical Pipeline&quot;">​</a></h2><p>Canonical ingestion flow:</p><ol><li>Source</li><li>Detect</li><li>Resolve domain / namespace</li><li>Register in QiArchive</li><li>Assign canonical identity</li><li>Assign short visible code</li><li>Normalize filename</li><li>Extract / inspect</li><li>Enrich metadata</li><li>Chunk</li><li>Embed locally</li><li>Index in vector store</li><li>Route / review / act</li></ol><h2 id="_4-3-state-model" tabindex="-1">4.3 State Model <a class="header-anchor" href="#_4-3-state-model" aria-label="Permalink to &quot;4.3 State Model&quot;">​</a></h2><p>Every item should have a visible processing state.</p><p>Recommended states:</p><ul><li><code>detected</code></li><li><code>registered</code></li><li><code>normalized</code></li><li><code>extracted</code></li><li><code>enriched</code></li><li><code>chunked</code></li><li><code>embedded</code></li><li><code>indexed</code></li><li><code>review_pending</code></li><li><code>routed</code></li><li><code>finalized</code></li><li><code>failed</code></li></ul><p>Failures must be:</p><ul><li>visible</li><li>stateful</li><li>retryable</li><li>tied to canonical IDs</li></ul><p>No silent failure. Silent failure is trash. Burn it.</p><h2 id="_4-4-ingestion-ledger" tabindex="-1">4.4 Ingestion Ledger <a class="header-anchor" href="#_4-4-ingestion-ledger" aria-label="Permalink to &quot;4.4 Ingestion Ledger&quot;">​</a></h2><p>Every ingestion run should be logged.</p><p>Minimum fields:</p><ul><li><code>ingestion_run_id</code></li><li><code>source_id</code></li><li><code>source_path</code></li><li><code>source_hash</code></li><li><code>file_size</code></li><li><code>detected_type</code></li><li><code>extraction_method</code></li><li><code>chunk_count</code></li><li><code>embedding_model</code></li><li><code>vector_collection</code></li><li><code>graph_update_status</code></li><li><code>started_at</code></li><li><code>completed_at</code></li><li><code>status</code></li><li><code>error_message</code></li></ul><h2 id="_4-5-stable-ids" tabindex="-1">4.5 Stable IDs <a class="header-anchor" href="#_4-5-stable-ids" aria-label="Permalink to &quot;4.5 Stable IDs&quot;">​</a></h2><p>Every document and chunk needs stable identity.</p><p>Minimum identity fields:</p><ul><li><code>source_id</code></li><li><code>document_id</code></li><li><code>chunk_id</code></li><li><code>canonical_path</code></li><li><code>original_path</code></li><li><code>hash</code></li><li><code>version</code></li><li><code>qicode</code> or short code, where applicable</li></ul><h2 id="_4-6-chunking-rules" tabindex="-1">4.6 Chunking Rules <a class="header-anchor" href="#_4-6-chunking-rules" aria-label="Permalink to &quot;4.6 Chunking Rules&quot;">​</a></h2><p>Chunking should preserve traceability.</p><p>Each chunk should include:</p><ul><li><code>chunk_id</code></li><li><code>document_id</code></li><li><code>source_id</code></li><li><code>chunk_index</code></li><li>text</li><li>heading or context, if available</li><li>page number, if available</li><li>byte or character offsets, if available</li><li>source path</li><li><code>created_at</code></li><li>embedding status</li></ul><p>Chunks should never float loose without source context.</p><hr><h1 id="_5-paperless-ngx-role" tabindex="-1">5. Paperless-NGX Role <a class="header-anchor" href="#_5-paperless-ngx-role" aria-label="Permalink to &quot;5. Paperless-NGX Role&quot;">​</a></h1><h2 id="_5-1-paperless-is-intake-not-the-brain" tabindex="-1">5.1 Paperless Is Intake, Not the Brain <a class="header-anchor" href="#_5-1-paperless-is-intake-not-the-brain" aria-label="Permalink to &quot;5.1 Paperless Is Intake, Not the Brain&quot;">​</a></h2><p>Paperless-NGX should be used as the document engine for:</p><ul><li>scanning</li><li>OCR</li><li>dedupe support</li><li>document metadata</li><li>document storage</li><li>searchable archive</li></ul><p>Paperless should not become the full AI system.</p><h2 id="_5-2-downstream-ai-pipeline" tabindex="-1">5.2 Downstream AI Pipeline <a class="header-anchor" href="#_5-2-downstream-ai-pipeline" aria-label="Permalink to &quot;5.2 Downstream AI Pipeline&quot;">​</a></h2><p>Paperless should feed:</p><ol><li>Canonical SQL registry</li><li>Text extraction</li><li>Chunks</li><li>Qdrant embeddings</li><li>Neo4j graph</li><li>QiNote / QiAccess views</li></ol><h2 id="_5-3-do-not-run-heavy-ai-inside-paperless" tabindex="-1">5.3 Do Not Run Heavy AI Inside Paperless <a class="header-anchor" href="#_5-3-do-not-run-heavy-ai-inside-paperless" aria-label="Permalink to &quot;5.3 Do Not Run Heavy AI Inside Paperless&quot;">​</a></h2><p>Rule:</p><p><strong>Paperless does Paperless. The AI pipeline does AI pipeline.</strong></p><p>Do not overload the Paperless container with heavy AI, graph, or embedding responsibilities.</p><h2 id="_5-4-test-before-bulk-import" tabindex="-1">5.4 Test Before Bulk Import <a class="header-anchor" href="#_5-4-test-before-bulk-import" aria-label="Permalink to &quot;5.4 Test Before Bulk Import&quot;">​</a></h2><p>Before mass importing documents:</p><ul><li>test with 10 documents</li><li>confirm OCR quality</li><li>confirm metadata rules</li><li>confirm filename format</li><li>confirm dedupe behavior</li><li>confirm storage paths</li><li>confirm export and recovery strategy</li></ul><p>Do not feed the beast a mountain of chaos and then act shocked when it burps fire.</p><hr><h1 id="_6-qinexus-relationship" tabindex="-1">6. QiNexus Relationship <a class="header-anchor" href="#_6-qinexus-relationship" aria-label="Permalink to &quot;6. QiNexus Relationship&quot;">​</a></h1><h2 id="_6-1-qinexus-is-the-source-library" tabindex="-1">6.1 QiNexus Is the Source Library <a class="header-anchor" href="#_6-1-qinexus-is-the-source-library" aria-label="Permalink to &quot;6.1 QiNexus Is the Source Library&quot;">​</a></h2><p>QiNexus is the human-facing source library and workspace.</p><p>QiNote should read from and write back to QiNexus-compatible structures where appropriate.</p><h2 id="_6-2-preferred-root-buckets" tabindex="-1">6.2 Preferred Root Buckets <a class="header-anchor" href="#_6-2-preferred-root-buckets" aria-label="Permalink to &quot;6.2 Preferred Root Buckets&quot;">​</a></h2><p>Canonical QiNexus root order:</p><ol start="0"><li>inbox</li><li>workbench</li><li>timeline</li><li>life</li><li>people</li><li>business</li><li>finance</li><li>legal</li><li>tech</li><li>assets</li><li>data</li><li>reference</li><li>archive</li><li>system</li></ol><p>Numbered variant:</p><ul><li><code>00_inbox</code></li><li><code>01_workbench</code></li><li><code>02_timeline</code></li><li><code>03_life</code></li><li><code>04_people</code></li><li><code>05_business</code></li><li><code>06_finance</code></li><li><code>07_legal</code></li><li><code>08_tech</code></li><li><code>09_assets</code></li><li><code>10_data</code></li><li><code>11_reference</code></li><li><code>12_archive</code></li><li><code>13_system</code></li></ul><h2 id="_6-3-qinexus-is-not-qinote" tabindex="-1">6.3 QiNexus Is Not QiNote <a class="header-anchor" href="#_6-3-qinexus-is-not-qinote" aria-label="Permalink to &quot;6.3 QiNexus Is Not QiNote&quot;">​</a></h2><p>QiNexus stores and organizes the source material.</p><p>QiNote interprets, links, recalls, and works with that material.</p><p>Do not collapse them into one vague folder blob.</p><hr><h1 id="_7-qiaccess-relationship" tabindex="-1">7. QiAccess Relationship <a class="header-anchor" href="#_7-qiaccess-relationship" aria-label="Permalink to &quot;7. QiAccess Relationship&quot;">​</a></h1><h2 id="_7-1-qiaccess-is-the-front-door" tabindex="-1">7.1 QiAccess Is the Front Door <a class="header-anchor" href="#_7-1-qiaccess-is-the-front-door" aria-label="Permalink to &quot;7.1 QiAccess Is the Front Door&quot;">​</a></h2><p>QiAccess should expose QiNote through clean modules and links.</p><p>QiAccess root doctrine:</p><ul><li>Home</li><li>Start</li><li>Capture</li><li>Knowledge</li><li>Memory</li><li>Insights</li><li>System</li></ul><p>Do not add extra top-level sections casually.</p><h2 id="_7-2-qinote-views-in-qiaccess" tabindex="-1">7.2 QiNote Views in QiAccess <a class="header-anchor" href="#_7-2-qinote-views-in-qiaccess" aria-label="Permalink to &quot;7.2 QiNote Views in QiAccess&quot;">​</a></h2><p>QiAccess can provide:</p><ul><li>capture form</li><li>knowledge browser</li><li>memory search</li><li>graph viewer</li><li>timeline view</li><li>ingestion status page</li><li>recent notes</li><li>source lookup</li><li>admin and system diagnostics</li></ul><p>QiAccess should not become the source of truth.</p><hr><h1 id="_8-capture-model-to-preserve" tabindex="-1">8. Capture Model to Preserve <a class="header-anchor" href="#_8-capture-model-to-preserve" aria-label="Permalink to &quot;8. Capture Model to Preserve&quot;">​</a></h1><h2 id="_8-1-capture-modes" tabindex="-1">8.1 Capture Modes <a class="header-anchor" href="#_8-1-capture-modes" aria-label="Permalink to &quot;8.1 Capture Modes&quot;">​</a></h2><p>Known useful capture modes:</p><ul><li>quick note</li><li>task / reminder</li><li>care observation</li><li>legal / finance note</li><li>link save</li></ul><h2 id="_8-2-capture-targets" tabindex="-1">8.2 Capture Targets <a class="header-anchor" href="#_8-2-capture-targets" aria-label="Permalink to &quot;8.2 Capture Targets&quot;">​</a></h2><p>Recommended targets:</p><ul><li>QiNexus inbox</li><li>Paperless</li><li>Knowledge</li><li>System storage</li><li>Timeline</li><li>Finance</li><li>Legal</li><li>Tech</li><li>Reference</li></ul><h2 id="_8-3-capture-doctrine" tabindex="-1">8.3 Capture Doctrine <a class="header-anchor" href="#_8-3-capture-doctrine" aria-label="Permalink to &quot;8.3 Capture Doctrine&quot;">​</a></h2><p>Capture should be fast and forgiving.</p><p>Processing should be structured and controlled.</p><p>Flow:</p><p>Capture → Inbox → Classify → Enrich → Route → Link → Index → Review</p><hr><h1 id="_9-naming-ids-and-file-doctrine" tabindex="-1">9. Naming, IDs, and File Doctrine <a class="header-anchor" href="#_9-naming-ids-and-file-doctrine" aria-label="Permalink to &quot;9. Naming, IDs, and File Doctrine&quot;">​</a></h1><h2 id="_9-1-naming-principle" tabindex="-1">9.1 Naming Principle <a class="header-anchor" href="#_9-1-naming-principle" aria-label="Permalink to &quot;9.1 Naming Principle&quot;">​</a></h2><p>Use short, readable names with stable machine identity underneath.</p><h2 id="_9-2-filename-direction" tabindex="-1">9.2 Filename Direction <a class="header-anchor" href="#_9-2-filename-direction" aria-label="Permalink to &quot;9.2 Filename Direction&quot;">​</a></h2><p>Preserve this direction:</p><ul><li>readable normalized base name</li><li>domain prefix, where useful</li><li>short visible code, where useful</li><li>full identity in metadata / registry</li></ul><h2 id="_9-3-short-code-direction" tabindex="-1">9.3 Short Code Direction <a class="header-anchor" href="#_9-3-short-code-direction" aria-label="Permalink to &quot;9.3 Short Code Direction&quot;">​</a></h2><p>A prior useful convention:</p><ul><li>short visible file suffix = <code>Q</code> + 6 uppercase hex characters</li></ul><p>Example pattern:</p><ul><li><code>{domain_prefix}_{normalized_base}_{short_code}.{ext}</code></li></ul><h2 id="_9-4-date-handling" tabindex="-1">9.4 Date Handling <a class="header-anchor" href="#_9-4-date-handling" aria-label="Permalink to &quot;9.4 Date Handling&quot;">​</a></h2><p>Dates should be embedded where they add clarity, ordering, or retrieval value.</p><p>Acceptable date formats:</p><ul><li><code>YYYY-MM-DD</code> for readable files</li><li><code>YYYYMMDD</code> or <code>YYMMDD</code> for compact codes</li></ul><p>For standalone Markdown files, preferred format:</p><ul><li><code>yyyy-mm-dd_{title_name}.md</code></li></ul><h2 id="_9-5-folder-numbering" tabindex="-1">9.5 Folder Numbering <a class="header-anchor" href="#_9-5-folder-numbering" aria-label="Permalink to &quot;9.5 Folder Numbering&quot;">​</a></h2><p>All important folder systems should be numbered so order is intentional, not alphabetical.</p><p>Use decimal-style or numeric prefixes where useful.</p><hr><h1 id="_10-markdown-and-publishing-doctrine" tabindex="-1">10. Markdown and Publishing Doctrine <a class="header-anchor" href="#_10-markdown-and-publishing-doctrine" aria-label="Permalink to &quot;10. Markdown and Publishing Doctrine&quot;">​</a></h1><h2 id="_10-1-markdown-first" tabindex="-1">10.1 Markdown-First <a class="header-anchor" href="#_10-1-markdown-first" aria-label="Permalink to &quot;10.1 Markdown-First&quot;">​</a></h2><p>QiNote should remain Markdown-first where practical.</p><p>Benefits:</p><ul><li>readable without app lock-in</li><li>Git-friendly</li><li>AI-indexable</li><li>portable</li><li>easy to publish</li><li>easy to back up</li><li>compatible with Obsidian, Wiki.js, and static site bridges</li></ul><h2 id="_10-2-publish-rules" tabindex="-1">10.2 Publish Rules <a class="header-anchor" href="#_10-2-publish-rules" aria-label="Permalink to &quot;10.2 Publish Rules&quot;">​</a></h2><p>Default privacy is private.</p><p>Only publish files with explicit approval:</p><p><code>publish: true</code></p><p>Never publish:</p><ul><li>secrets</li><li>temp files</li><li>unapproved drafts</li><li>private notes</li><li>raw evidence unless intentionally shared</li><li>system credentials</li><li>ingestion logs containing sensitive paths or keys</li></ul><h2 id="_10-3-static-export" tabindex="-1">10.3 Static Export <a class="header-anchor" href="#_10-3-static-export" aria-label="Permalink to &quot;10.3 Static Export&quot;">​</a></h2><p>QiNote should support future static export and publishing for approved content.</p><p>Possible consumers:</p><ul><li>QiAccess static site</li><li>Cloudflare Pages</li><li>public knowledge pages</li><li>family / household docs</li><li>client-safe documentation</li></ul><hr><h1 id="_11-graph-and-rag-doctrine" tabindex="-1">11. Graph and RAG Doctrine <a class="header-anchor" href="#_11-graph-and-rag-doctrine" aria-label="Permalink to &quot;11. Graph and RAG Doctrine&quot;">​</a></h1><h2 id="_11-1-graphify-role" tabindex="-1">11.1 Graphify Role <a class="header-anchor" href="#_11-1-graphify-role" aria-label="Permalink to &quot;11.1 Graphify Role&quot;">​</a></h2><p>Graphify or similar tools are useful as mapping and visualization layers.</p><p>They are not sources of truth.</p><p>Use them to generate:</p><ul><li><code>graph.html</code></li><li><code>graph.json</code></li><li><code>GRAPH_REPORT.md</code></li><li>dependency maps</li><li>file relationship views</li></ul><p>Preserve Markdown, files, and registry records as truth.</p><h2 id="_11-2-qdrant-role" tabindex="-1">11.2 Qdrant Role <a class="header-anchor" href="#_11-2-qdrant-role" aria-label="Permalink to &quot;11.2 Qdrant Role&quot;">​</a></h2><p>Qdrant stores semantic embeddings for retrieval.</p><p>It should answer:</p><ul><li>similar notes</li><li>related documents</li><li>semantic search</li><li>memory recall</li><li>context assembly</li></ul><h2 id="_11-3-neo4j-role" tabindex="-1">11.3 Neo4j Role <a class="header-anchor" href="#_11-3-neo4j-role" aria-label="Permalink to &quot;11.3 Neo4j Role&quot;">​</a></h2><p>Neo4j stores relationships.</p><p>It should answer:</p><ul><li>who is connected to what</li><li>which projects touch which files</li><li>which decisions came from which events</li><li>legal, finance, and care timeline relationships</li><li>system dependency graphs</li></ul><h2 id="_11-4-rag-rule" tabindex="-1">11.4 RAG Rule <a class="header-anchor" href="#_11-4-rag-rule" aria-label="Permalink to &quot;11.4 RAG Rule&quot;">​</a></h2><p>RAG must be source-backed.</p><p>No answer should pretend confidence without retrievable source context.</p><p>Every serious AI response should support:</p><ul><li>source references</li><li>confidence / uncertainty</li><li>date awareness</li><li>object links</li><li>chunk lineage</li></ul><hr><h1 id="_12-structured-data-doctrine" tabindex="-1">12. Structured Data Doctrine <a class="header-anchor" href="#_12-structured-data-doctrine" aria-label="Permalink to &quot;12. Structured Data Doctrine&quot;">​</a></h1><h2 id="_12-1-sql-registry" tabindex="-1">12.1 SQL Registry <a class="header-anchor" href="#_12-1-sql-registry" aria-label="Permalink to &quot;12.1 SQL Registry&quot;">​</a></h2><p>A canonical SQL registry should track confirmed structured data.</p><p>Use SQL / Postgres / NocoDB for things like:</p><ul><li>document registry</li><li>ingestion ledger</li><li>accounts</li><li>vendors</li><li>finance data</li><li>task records</li><li>event records</li><li>source metadata</li><li>object relationships where graph storage is not required</li></ul><h2 id="_12-2-do-not-put-everything-in-sql" tabindex="-1">12.2 Do Not Put Everything in SQL <a class="header-anchor" href="#_12-2-do-not-put-everything-in-sql" aria-label="Permalink to &quot;12.2 Do Not Put Everything in SQL&quot;">​</a></h2><p>Not every Markdown file needs to be converted into database rows.</p><p>Rule:</p><ul><li>Source content can stay as files.</li><li>Confirmed metadata goes into the registry.</li><li>Relationships go into the graph.</li><li>Embeddings go into the vector store.</li><li>The UI reads from all layers.</li></ul><hr><h1 id="_13-security-and-exposure-rules" tabindex="-1">13. Security and Exposure Rules <a class="header-anchor" href="#_13-security-and-exposure-rules" aria-label="Permalink to &quot;13. Security and Exposure Rules&quot;">​</a></h1><h2 id="_13-1-private-by-default" tabindex="-1">13.1 Private by Default <a class="header-anchor" href="#_13-1-private-by-default" aria-label="Permalink to &quot;13.1 Private by Default&quot;">​</a></h2><p>QiNote should assume private data.</p><p>Admin tools should be local or private unless explicitly exposed.</p><h2 id="_13-2-service-exposure" tabindex="-1">13.2 Service Exposure <a class="header-anchor" href="#_13-2-service-exposure" aria-label="Permalink to &quot;13.2 Service Exposure&quot;">​</a></h2><p>Preferred exposure model:</p><ul><li>localhost-bound services</li><li>Tailscale for personal device access</li><li>Cloudflare only for approved public or static surfaces</li><li>no broad public admin dashboards</li><li>secrets stored in <code>.env</code></li><li>no credentials committed to repos</li></ul><h2 id="_13-3-ollama-warning" tabindex="-1">13.3 Ollama Warning <a class="header-anchor" href="#_13-3-ollama-warning" aria-label="Permalink to &quot;13.3 Ollama Warning&quot;">​</a></h2><p>Ollama should generally be localhost-only unless intentionally opened through LAN or Tailscale with firewall controls.</p><p>Preferred:</p><ul><li><code>OLLAMA_HOST=127.0.0.1:11434</code></li></ul><p>Avoid casual <code>0.0.0.0</code> exposure.</p><hr><h1 id="_14-ui-ux-goals" tabindex="-1">14. UI / UX Goals <a class="header-anchor" href="#_14-ui-ux-goals" aria-label="Permalink to &quot;14. UI / UX Goals&quot;">​</a></h1><h2 id="_14-1-qinote-should-feel-like-a-calm-control-room" tabindex="-1">14.1 QiNote Should Feel Like a Calm Control Room <a class="header-anchor" href="#_14-1-qinote-should-feel-like-a-calm-control-room" aria-label="Permalink to &quot;14.1 QiNote Should Feel Like a Calm Control Room&quot;">​</a></h2><p>QiNote should not feel like a cluttered admin panel.</p><p>Core UI needs:</p><ul><li>quick capture</li><li>search</li><li>source lookup</li><li>recent activity</li><li>timeline</li><li>graph view</li><li>object view</li><li>ingestion status</li><li>review queue</li><li>publish / private controls</li></ul><h2 id="_14-2-low-cognitive-load" tabindex="-1">14.2 Low Cognitive Load <a class="header-anchor" href="#_14-2-low-cognitive-load" aria-label="Permalink to &quot;14.2 Low Cognitive Load&quot;">​</a></h2><p>The interface should support ADHD-friendly workflows:</p><ul><li>fast capture</li><li>minimal required fields</li><li>progressive enrichment</li><li>clear next action</li><li>visible status</li><li>no mystery queues</li><li>no hidden failure</li><li>filters instead of folder digging</li></ul><h2 id="_14-3-review-queue" tabindex="-1">14.3 Review Queue <a class="header-anchor" href="#_14-3-review-queue" aria-label="Permalink to &quot;14.3 Review Queue&quot;">​</a></h2><p>QiNote needs a human review layer.</p><p>The review queue should show:</p><ul><li>unclassified captures</li><li>failed ingestions</li><li>low-confidence extracted metadata</li><li>duplicate candidates</li><li>source conflicts</li><li>publish candidates</li><li>orphan chunks</li><li>graph relationship suggestions</li></ul><hr><h1 id="_15-qinote-module-requirements" tabindex="-1">15. QiNote Module Requirements <a class="header-anchor" href="#_15-qinote-module-requirements" aria-label="Permalink to &quot;15. QiNote Module Requirements&quot;">​</a></h1><h2 id="_15-1-mvp-requirements" tabindex="-1">15.1 MVP Requirements <a class="header-anchor" href="#_15-1-mvp-requirements" aria-label="Permalink to &quot;15.1 MVP Requirements&quot;">​</a></h2><p>QiNote MVP should include:</p><ol><li>Quick capture inbox</li><li>Markdown-backed notes</li><li>Basic object registry</li><li>Source / document registry</li><li>Local search</li><li>Paperless document link support</li><li>Ingestion ledger</li><li>Chunking pipeline</li><li>Qdrant embedding search</li><li>Neo4j relationship sync</li><li>Admin status UI</li><li>Review queue</li><li>Exportable Markdown</li><li>Source-backed AI answer endpoint</li></ol><h2 id="_15-2-later-requirements" tabindex="-1">15.2 Later Requirements <a class="header-anchor" href="#_15-2-later-requirements" aria-label="Permalink to &quot;15.2 Later Requirements&quot;">​</a></h2><p>Later versions can add:</p><ul><li>voice capture</li><li>mobile PWA</li><li>timeline builder</li><li>graph explorer</li><li>automated summaries</li><li>calendar and email ingestion</li><li>local LLM chat interface</li><li>publishable knowledge pages</li><li>family and care dashboards</li><li>legal and evidence bundles</li><li>finance / source reconciliation</li><li>personal memory assistant</li></ul><hr><h1 id="_16-suggested-qinote-folder-module-shape" tabindex="-1">16. Suggested QiNote Folder / Module Shape <a class="header-anchor" href="#_16-suggested-qinote-folder-module-shape" aria-label="Permalink to &quot;16. Suggested QiNote Folder / Module Shape&quot;">​</a></h1><p>This is a proposed carry-forward shape, not a rigid final tree.</p><h2 id="_16-1-code-app-side" tabindex="-1">16.1 Code / App Side <a class="header-anchor" href="#_16-1-code-app-side" aria-label="Permalink to &quot;16.1 Code / App Side&quot;">​</a></h2><ul><li><p><code>apps/qinote/</code></p><ul><li>frontend UI</li><li>capture interface</li><li>note browser</li><li>search views</li><li>review queue</li><li>graph / timeline views</li></ul></li><li><p><code>services/ai_ingestion/</code></p><ul><li>source detection</li><li>text extraction</li><li>chunking</li><li>embeddings</li><li>Qdrant sync</li><li>Neo4j sync</li><li>ingestion ledger</li></ul></li><li><p><code>services/qinote_api/</code></p><ul><li>object API</li><li>notes API</li><li>search API</li><li>source lookup API</li><li>AI answer endpoint</li></ul></li><li><p><code>docs/qinote/</code></p><ul><li>doctrine</li><li>architecture</li><li>object model</li><li>ingestion contract</li><li>naming contract</li><li>ADRs</li><li>runbooks</li></ul></li></ul><h2 id="_16-2-knowledge-side" tabindex="-1">16.2 Knowledge Side <a class="header-anchor" href="#_16-2-knowledge-side" aria-label="Permalink to &quot;16.2 Knowledge Side&quot;">​</a></h2><ul><li><code>00_inbox/</code></li><li><code>01_workbench/</code></li><li><code>02_timeline/</code></li><li><code>03_life/</code></li><li><code>04_people/</code></li><li><code>05_business/</code></li><li><code>06_finance/</code></li><li><code>07_legal/</code></li><li><code>08_tech/</code></li><li><code>09_assets/</code></li><li><code>10_data/</code></li><li><code>11_reference/</code></li><li><code>12_archive/</code></li><li><code>13_system/</code></li></ul><hr><h1 id="_17-what-to-archive-from-the-retired-project" tabindex="-1">17. What to Archive From the Retired Project <a class="header-anchor" href="#_17-what-to-archive-from-the-retired-project" aria-label="Permalink to &quot;17. What to Archive From the Retired Project&quot;">​</a></h1><p>Archive but do not actively carry forward:</p><ul><li>duplicate folder trees</li><li>old business blueprint scaffolding</li><li>vague <code>nexus_core</code> terminology</li><li>obsolete route structures</li><li>experimental naming that conflicts with QiNexus / QiArchive / QiNote doctrine</li><li>anything that makes QiAccess the source of truth</li><li>any pipeline that skips canonical IDs</li><li>any AI memory concept without source references</li><li>any public publishing flow without <code>publish: true</code></li></ul><p>Recommended archive destination:</p><ul><li><code>docs/legacy/Legacy_QiOS_Business_Blueprint_Extracts.md</code></li></ul><hr><h1 id="_18-what-to-preserve-as-active-qinote-doctrine" tabindex="-1">18. What to Preserve as Active QiNote Doctrine <a class="header-anchor" href="#_18-what-to-preserve-as-active-qinote-doctrine" aria-label="Permalink to &quot;18. What to Preserve as Active QiNote Doctrine&quot;">​</a></h1><p>Preserve these as active doctrine:</p><ol><li>QiNote is the local-first knowledge and memory layer.</li><li>Source files remain truth.</li><li>Derived indexes must point to source.</li><li>QiArchive owns the ingestion and memory pipeline.</li><li>QiNexus is the human source workspace.</li><li>QiAccess is the front door.</li><li>Paperless handles OCR and document intake.</li><li>Qdrant handles semantic retrieval.</li><li>Neo4j handles relationships.</li><li>Metadata comes before automation.</li><li>Stable IDs are mandatory.</li><li>Every ingestion run is logged.</li><li>Every chunk is traceable.</li><li>Failures must be visible and retryable.</li><li>Markdown remains the portable base layer.</li><li>Publishing is private by default and explicit only.</li><li>Folder order should be intentional and numbered.</li><li>Object-based notes matter more than page clutter.</li><li>Timeline reconstruction is a core use case.</li><li>AI recall must be grounded, not vibes in a trench coat.</li></ol><hr><h1 id="_19-recommended-next-build-order" tabindex="-1">19. Recommended Next Build Order <a class="header-anchor" href="#_19-recommended-next-build-order" aria-label="Permalink to &quot;19. Recommended Next Build Order&quot;">​</a></h1><h2 id="phase-1-—-freeze-doctrine" tabindex="-1">Phase 1 — Freeze Doctrine <a class="header-anchor" href="#phase-1-—-freeze-doctrine" aria-label="Permalink to &quot;Phase 1 — Freeze Doctrine&quot;">​</a></h2><p>Create or update:</p><ul><li><code>docs/qinote/00_readme.md</code></li><li><code>docs/qinote/10_doctrine.md</code></li><li><code>docs/qinote/20_architecture.md</code></li><li><code>docs/qinote/30_object_model.md</code></li><li><code>docs/qinote/40_ingestion_pipeline.md</code></li><li><code>docs/qinote/50_security_exposure.md</code></li><li><code>docs/qinote/60_roadmap.md</code></li></ul><h2 id="phase-2-—-build-the-ingestion-spine" tabindex="-1">Phase 2 — Build the Ingestion Spine <a class="header-anchor" href="#phase-2-—-build-the-ingestion-spine" aria-label="Permalink to &quot;Phase 2 — Build the Ingestion Spine&quot;">​</a></h2><p>Build:</p><ul><li>source registry</li><li>ingestion ledger</li><li>text extractor</li><li>chunker</li><li>embedding worker</li><li>Qdrant writer</li><li>Neo4j writer</li><li>retryable failure states</li></ul><h2 id="phase-3-—-build-the-qinote-ui" tabindex="-1">Phase 3 — Build the QiNote UI <a class="header-anchor" href="#phase-3-—-build-the-qinote-ui" aria-label="Permalink to &quot;Phase 3 — Build the QiNote UI&quot;">​</a></h2><p>Build:</p><ul><li>quick capture</li><li>inbox</li><li>note list</li><li>document / source view</li><li>search</li><li>review queue</li><li>ingestion status</li></ul><h2 id="phase-4-—-add-ai-recall" tabindex="-1">Phase 4 — Add AI Recall <a class="header-anchor" href="#phase-4-—-add-ai-recall" aria-label="Permalink to &quot;Phase 4 — Add AI Recall&quot;">​</a></h2><p>Build:</p><ul><li>source-backed ask endpoint</li><li>context assembler</li><li>citation / source viewer</li><li>confidence labels</li><li>memory search</li></ul><h2 id="phase-5-—-add-graph-timeline" tabindex="-1">Phase 5 — Add Graph + Timeline <a class="header-anchor" href="#phase-5-—-add-graph-timeline" aria-label="Permalink to &quot;Phase 5 — Add Graph + Timeline&quot;">​</a></h2><p>Build:</p><ul><li>relationship viewer</li><li>timeline builder</li><li>object graph</li><li>project / person / source maps</li></ul><hr><h1 id="_20-codex-transfer-prompt" tabindex="-1">20. Codex Transfer Prompt <a class="header-anchor" href="#_20-codex-transfer-prompt" aria-label="Permalink to &quot;20. Codex Transfer Prompt&quot;">​</a></h1><p>Use this when telling Codex to implement the carry-forward QiNote module:</p><blockquote><p>We are retiring an older project and preserving only the durable QiNote architecture. Build QiNote as the local-first knowledge, notes, memory, and retrieval module of the Qi ecosystem. Source files remain truth. Derived systems must point back to source. QiNexus is the human source workspace, QiArchive owns the ingestion and memory pipeline, QiAccess is the front door, Paperless-NGX handles document OCR and intake, Qdrant handles vector search, and Neo4j handles relationships. Build a simple, readable MVP with a source registry, ingestion ledger, stable IDs, chunking, local embeddings, Qdrant indexing, Neo4j graph sync, review queue, Markdown-backed notes, quick capture, and source-backed AI answer endpoint. Keep admin and private services local or Tailscale-only. Use <code>.env</code> for secrets. Prioritize a working pipeline over overengineering. Every document and chunk must have <code>source_id</code>, <code>document_id</code>, <code>chunk_id</code>, <code>source_path</code>, <code>hash</code>, <code>ingestion_run_id</code>, and <code>status</code>. Failures must be visible, stateful, retryable, and tied to canonical IDs.</p></blockquote><hr><h1 id="_21-final-north-star" tabindex="-1">21. Final North Star <a class="header-anchor" href="#_21-final-north-star" aria-label="Permalink to &quot;21. Final North Star&quot;">​</a></h1><p>QiNote should become the system where captured reality becomes structured memory.</p><p>Not another notes app.</p><p>A private, local-first, source-backed knowledge engine that can answer:</p><ul><li>what happened</li><li>what matters</li><li>where the proof is</li><li>what connects</li><li>what changed</li><li>what needs action</li><li>what should be remembered</li></ul>',306)])])}const m=i(t,[["render",r]]);export{p as __pageData,m as default};
